 1→import type { NextConfig } from "next";
 2→import createNextIntlPlugin from "next-intl/plugin";
 3→import { withSentryConfig } from "@sentry/nextjs";
 4→
 5→type NextConfigWithCompiler = NextConfig & {
 6→  cacheComponents?: boolean;
 7→  reactCompiler?: boolean;
 8→};
 9→
10→// SEC-03: Content-Security-Policy in Report-Only mode.
11→// Allows: WebGL (Three.js), inline styles (Tailwind), Sentry, Google Fonts, Telegram.
12→const cspDirectives = [
13→  "default-src 'self'",
14→  "script-src 'self' 'unsafe-eval' 'unsafe-inline' https://telegram.org https://*.sentry.io",
15→  "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
16→  "img-src 'self' data: blob: https:",
17→  "font-src 'self' https://fonts.gstatic.com",
18→  "connect-src 'self' https://*.sentry.io https://*.ingest.sentry.io wss: ws:",
19→  "worker-src 'self' blob:",
20→  "frame-src 'self' https://oauth.telegram.org",
21→  "object-src 'none'",
22→  "base-uri 'self'",
23→  "form-action 'self'",
24→].join("; ");
25→
26→const config: NextConfigWithCompiler = {
27→  experimental: {},
28→  cacheComponents: true,
29→  reactCompiler: true,
30→  skipTrailingSlashRedirect: true,
31→  async headers() {
32→    return [
33→      {
34→        source: "/(.*)",
35→        headers: [
36→          {
37→            key: "Content-Security-Policy-Report-Only",
38→            value: cspDirectives,
39→          },
40→        ],
41→      },
42→    ];
43→  },
44→  async rewrites() {
45→    return [
46→      {
47→        source: "/api/v1/:path*",
48→        destination: "http://localhost:8000/api/v1/:path*",
49→      },
50→    ];
51→  },
52→};
53→
54→const withNextIntl = createNextIntlPlugin();
55→
56→export default withSentryConfig(withNextIntl(config), {
57→  // Suppress source map upload warnings when SENTRY_AUTH_TOKEN is not set
58→  silent: !process.env.SENTRY_AUTH_TOKEN,
59→
60→  // Upload source maps for readable stack traces
61→  widenClientFileUpload: true,
62→
63→  // Automatically tree-shake unused Sentry code
64→  disableLogger: true,
65→});
